// Filter for engagement-worthy replies
const mentions = $('Fetch New Mentions').all();
const comments = $('Fetch IG Comments').all();

const all = [...mentions, ...comments];

const scored = all.map(item => {
  const text = (item.json.text || item.json.comment || '').toLowerCase();
  let score = 0;
  let category = 'general';

  // Questions get priority
  if (text.includes('?')) { score += 3; category = 'question'; }
  // Purchase intent
  if (text.match(/price|buy|cost|how much|order|available/)) { score += 5; category = 'purchase_intent'; }
  // Complaint
  if (text.match(/bad|terrible|worst|hate|broken|broken|refund/)) { score += 4; category = 'complaint'; }
  // Praise
  if (text.match(/love|amazing|great|awesome|best|thank/)) { score += 2; category = 'praise'; }

  return { json: { ...item.json, score, category, shouldReply: score >= 3 } };
});

return scored.filter(s => s.json.shouldReply).sort((a, b) => b.json.score - a.json.score).slice(0, 10);
